args.sparql:
SELECT ?birthplaceLabel WHERE {
  ?player wdt:P27 wd:Q155 ;
         wdt:P106 wd:Q937841 ;
         wdt:P54 wd:Q80955 ;
         wdt:P19 ?birthplace ;
         wdt:P413 ?position .
  ?position wdt:P279* wd:Q193592 .  # midfielder or subclass
  ?birthplace rdfs:label ?birthplaceLabel .
  FILTER(LANG(?birthplaceLabel) = 'en')
} LIMIT 10

